const returnItems = [];

for (const item of $input.all()) {
  try {
    // 1. Drill down to grab the raw stringified JSON from the AI output
    let rawText = item.json.output[0].content[0].text;

    // 2. Strip out any markdown formatting just to be safe
    rawText = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();

    // 3. Parse that string into your clean JavaScript object
    const cleanJson = JSON.parse(rawText);

    // 4. OVERWRITE OWNER: Look into the 'owners' array and grab the displayName
    if (item.json.owners && item.json.owners.length > 0) {
        cleanJson["Owner (Recruiter/HM)"] = item.json.owners[0].displayName;
    }

    // 5. OVERWRITE DATE ADDED: Grab createdTime, split at 'T', and keep the date
    if (item.json.createdTime) {
        cleanJson["Date Added"] = item.json.createdTime.split('T')[0];
    }

    // 6. Attach the other top-level metadata just in case you need it
    cleanJson.original_file_name = item.json.name;
    cleanJson.original_file_id = item.json.id;

    // 7. Return the beautifully clean JSON
    returnItems.push({ json: cleanJson });

  } catch (error) {
    // Failsafe in case the AI completely breaks the JSON format
    returnItems.push({ 
      json: { 
        error: "Bro, the AI gave invalid JSON", 
        details: error.message 
      } 
    });
  }
}

return returnItems;

const sheetItems = $items("Get row(s) in sheet") || [];

const existingIds = new Set(
  sheetItems
    .map(item => item.json['FILE ID'])
    .filter(id => id)
);

// Collect new files
const newFiles = [];

for (const item of items) {
  const files = item.json.files || [];

  for (const file of files) {
    if (!file.id) continue;

    if (!existingIds.has(file.id)) {
      newFiles.push({
        json: file
      });
    }
  }
}

return newFiles;

const returnItems = [];

for (const item of $input.all()) {

  // 1. WIPE THE JSON DATA: Force the text metadata to say .zip
  if (item.json.name) {
    item.json.name = item.json.name.replace(/\.docx$/i, '.zip');
  }
  if (item.json.mimeType) {
    item.json.mimeType = 'application/zip';
  }

  // 2. WIPE THE BINARY DATA: Force the physical file to say .zip
  if (item.binary && item.binary.data) {
    item.binary.data.fileName = item.binary.data.fileName.replace(/\.docx$/i, '.zip');
    item.binary.data.mimeType = 'application/zip';
    item.binary.data.fileExtension = 'zip';
  }

  returnItems.push(item);
}

return returnItems;

const returnItems = [];

for (const item of $input.all()) {
  if (!item.binary) continue;

  for (const key of Object.keys(item.binary)) {
    const fileData = item.binary[key];

    // Find the one file that holds the resume text
    if (fileData.fileName === 'document.xml' || fileData.fileName === 'word/document.xml') {
      returnItems.push({
        json: { status: "Isolated the pure XML file!" },
        // We move it to the standard 'data' slot so the next node can easily read it
        binary: { data: fileData }
      });
    }
  }
}

return returnItems;

const returnItems = [];

for (const item of $input.all()) {
  // Grab that massive alien XML string you just showed me
  // Note: if your node output property is named something else, change 'data' to match it
  const xmlString = item.json.data; 

  if (xmlString) {
    // THE BULLDOZER: Destroy all XML tags <...> and leave only the human text
    let cleanText = xmlString.replace(/<[^>]+>/g, ' ');

    // Clean up any extra giant spaces it left behind
    cleanText = cleanText.replace(/\s+/g, ' ').trim();

    returnItems.push({
      json: {
        clean_resume_text: cleanText,
        status: "Bro, we did it."
      }
    });
  } else {
    returnItems.push({ json: { error: "No XML data found to clean." } });
  }
}

return returnItems;
